import torch
import torch.nn as nn
import torch.optim as optim
from torch.utils.data import DataLoader, Dataset
from torchvision import transforms
from torchvision.models import resnet18, ResNet18_Weights
from PIL import Image
import io
import requests

# --- Configuration ---
MODEL_URL = "https://download.pytorch.org/models/resnet18-f37072fd.pth" # Example URL for ResNet18
NUM_CLASSES = 10  # Example: Number of classes in your custom dataset
BATCH_SIZE = 32
LEARNING_RATE = 0.001
NUM_EPOCHS = 5
DEVICE = torch.device("cuda" if torch.cuda.is_available() else "cpu")

# --- Custom Dataset (Example) ---
# Replace this with your actual custom dataset loading logic
class CustomDataset(Dataset):
    def __init__(self, num_samples=100, transform=None):
        self.num_samples = num_samples
        self.transform = transform
        # Simulate some dummy data
        self.data = [torch.randn(3, 224, 224) for _ in range(num_samples)]
        self.labels = [torch.randint(0, NUM_CLASSES, (1,)).item() for _ in range(num_samples)]

    def __len__(self):
        return self.num_samples

    def __getitem__(self, idx):
        image = self.data[idx]
        label = self.labels[idx]
        if self.transform:
            # Convert tensor to PIL Image for torchvision transforms
            image = transforms.ToPILImage()(image)
            image = self.transform(image)
        return image, label

# --- Model Loading and Fine-tuning ---
def download_and_load_model(model_url, model_class, num_classes, device):
    print(f"Attempting to download model from: {model_url}")
    try:
        response = requests.get(model_url, stream=True)
        response.raise_for_status() # Raise an HTTPError for bad responses (4xx or 5xx)

        # Load the state_dict from the in-memory bytes
        model_bytes = io.BytesIO(response.content)
        state_dict = torch.load(model_bytes, map_location=device)
        print("Model state_dict downloaded successfully.")

        # Initialize the model architecture
        if model_class == resnet18:
            model = resnet18(weights=None) # Initialize with no pretrained weights from torchvision
            # Replace the final fully connected layer for fine-tuning
            num_ftrs = model.fc.in_features
            model.fc = nn.Linear(num_ftrs, num_classes)
        else:
            raise ValueError("Unsupported model class for automatic architecture setup.")

        model.load_state_dict(state_dict)
        print("Model loaded into architecture successfully.")
        return model.to(device)

    except requests.exceptions.RequestException as e:
        print(f"Error downloading model: {e}")
        print("Falling back to torchvision's built-in pretrained model (if available) or random initialization.")
        if model_class == resnet18:
            print("Loading ResNet18 with default torchvision pretrained weights.")
            model = resnet18(weights=ResNet18_Weights.IMAGENET1K_V1)
            num_ftrs = model.fc.in_features
            model.fc = nn.Linear(num_ftrs, num_classes)
            return model.to(device)
        else:
            print("Could not fall back to a known torchvision model. Initializing with random weights.")
            model = model_class()
            # Assuming a standard classification head replacement is needed
            if hasattr(model, 'fc'):
                num_ftrs = model.fc.in_features
                model.fc = nn.Linear(num_ftrs, num_classes)
            elif hasattr(model, 'classifier') and isinstance(model.classifier, nn.Sequential):
                # Example for models like VGG, DenseNet
                num_ftrs = model.classifier[-1].in_features
                model.classifier[-1] = nn.Linear(num_ftrs, num_classes)
            return model.to(device)
    except Exception as e:
        print(f"An unexpected error occurred during model loading: {e}")
        print("Falling back to torchvision's built-in pretrained model (if available) or random initialization.")
        if model_class == resnet18:
            print("Loading ResNet18 with default torchvision pretrained weights.")
            model = resnet18(weights=ResNet18_Weights.IMAGENET1K_V1)
            num_ftrs = model.fc.in_features
            model.fc = nn.Linear(num_ftrs, num_classes)
            return model.to(device)
        else:
            print("Could not fall back to a known torchvision model. Initializing with random weights.")
            model = model_class()
            if hasattr(model, 'fc'):
                num_ftrs = model.fc.in_features
                model.fc = nn.Linear(num_ftrs, num_classes)
            elif hasattr(model, 'classifier') and isinstance(model.classifier, nn.Sequential):
                num_ftrs = model.classifier[-1].in_features
                model.classifier[-1] = nn.Linear(num_ftrs, num_classes)
            return model.to(device)


def train_model(model, train_loader, criterion, optimizer, num_epochs, device):
    model.train()
    for epoch in range(num_epochs):
        running_loss = 0.0
        for i, (inputs, labels) in enumerate(train_loader):
            inputs, labels = inputs.to(device), labels.to(device)

            optimizer.zero_grad()

            outputs = model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()

            running_loss += loss.item() * inputs.size(0)

        epoch_loss = running_loss / len(train_loader.dataset)
        print(f"Epoch {epoch+1}/{num_epochs}, Loss: {epoch_loss:.4f}")
    print("Fine-tuning complete!")


def main():
    print(f"Using device: {DEVICE}")

    # 1. Define data transformations
    data_transforms = transforms.Compose([
        transforms.Resize(256),
        transforms.CenterCrop(224),
        transforms.ToTensor(),
        transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
    ])

    # 2. Create custom dataset and data loader
    # In a real scenario, you'd load your actual images and labels here.
    train_dataset = CustomDataset(num_samples=200, transform=data_transforms)
    train_loader = DataLoader(train_dataset, batch_size=BATCH_SIZE, shuffle=True)

    print(f"Training dataset size: {len(train_dataset)}")

    # 3. Download and load the pretrained model, then modify for fine-tuning
    model = download_and_load_model(MODEL_URL, resnet18, NUM_CLASSES, DEVICE)

    # 4. Define loss function and optimizer
    criterion = nn.CrossEntropyLoss()
    # Only optimize parameters that require gradients (e.g., the new fc layer)
    optimizer = optim.Adam(model.parameters(), lr=LEARNING_RATE)

    # 5. Fine-tune the model
    print("\nStarting fine-tuning...")
    train_model(model, train_loader, criterion, optimizer, NUM_EPOCHS, DEVICE)

    # 6. (Optional) Save the fine-tuned model
    torch.save(model.state_dict(), "fine_tuned_model.pth")
    print("Fine-tuned model saved to fine_tuned_model.pth")

    # 7. (Optional) Example of how to load and use the fine-tuned model for inference
    print("\nLoading fine-tuned model for inference example...")
    inference_model = resnet18(weights=None)
    num_ftrs = inference_model.fc.in_features
    inference_model.fc = nn.Linear(num_ftrs, NUM_CLASSES)
    inference_model.load_state_dict(torch.load("fine_tuned_model.pth", map_location=DEVICE))
    inference_model.to(DEVICE)
    inference_model.eval()

    # Simulate an inference step
    dummy_input = torch.randn(1, 3, 224, 224).to(DEVICE)
    with torch.no_grad():
        output = inference_model(dummy_input)
    print(f"Inference example output shape: {output.shape}")
    print(f"Predicted class (example): {torch.argmax(output, 1).item()}")


if __name__ == "__main__":
    main()